' "# Adaptive Rejection Sampling (ARS) implementation in R" "# Reference: Gilks & Wild (1992)" "" "# Main entry: ars()" "# Test entry: test()" "" "numeric_dlogf_factory <- function(logf, lower, upper) {" "  function(x) {" "    x <- as.numeric(x)" "    eps <- 1e-6 * (1 + abs(x))" "    xl <- pmax(lower, x - eps)" "    xr <- pmin(upper, x + eps)" "    # if at boundary, bias step inside" "    xl[xl == x] <- x[xl == x] - eps[xl == x] * 0.5" "    xr[xr == x] <- x[xr == x] + eps[xr == x] * 0.5" "    l1 <- logf(xr)" "    l0 <- logf(xl)" "    d <- (l1 - l0) / (xr - xl)" "    d[!is.finite(d)] <- NA_real_" "    d" "  }" "}" "" "validate_inputs <- function(f, n, lower, upper, dlogf) {" "  if (!is.function(f)) stop('f must be a function returning (unnormalized) density values')" "  if (!is.numeric(n) || length(n) != 1 || n <= 0 || n != as.integer(n)) stop('n must be a positive integer')" "  if (!is.numeric(lower) || !is.numeric(upper) || length(lower) != 1 || length(upper) != 1) stop('lower and upper must be numeric scalars')" "  if (!(lower < upper)) stop('lower must be strictly less than upper')" "  if (!is.null(dlogf) && !is.function(dlogf)) stop('dlogf must be NULL or a function')" "  invisible(TRUE)" "}" "" "make_logf <- function(f) {" "  function(x) {" "    y <- suppressWarnings(f(x))" "    out <- rep(-Inf, length(x))" "    ok <- is.finite(y) & (y > 0)" "    out[ok] <- log(y[ok])" "    out" "  }" "}" "" "compute_intersections <- function(x, h, hp, lower, upper) {
