" "" "build_upper_params <- function(x, h, hp) {" "  # returns a (intercepts) and b (slopes) of tangents u(x) = a + b x at abscissae" "  a <- h - hp * x" "  list(a = a, b = hp)" "}" "" "segment_integrals <- function(z, a, b) {" "  k <- length(a)" "  ints <- numeric(k)" "  for (i in 1:k) {" "    bi <- b[i]" "    ai <- a[i]" "    zl <- z[i]" "    zr <- z[i + 1]" "    if (!is.finite(zl) || !is.finite(zr)) {" "      # Require integrability: if b>0 and zr=Inf, diverges; if b<0 and zl=-Inf, diverges" "      if (is.infinite(zr) && bi > -1e-14) return(rep(NaN, k))" "      if (is.infinite(zl) && bi < 1e-14) return(rep(NaN, k))" "    }" "    if (abs(bi) < 1e-12) {" "      val <- exp(ai) * (zr - zl)" "    } else {" "      val <- exp(ai) / bi * (exp(bi * zr) - exp(bi * zl))" "    }" "    if (!is.finite(val) || val <= 0) return(rep(NaN, k))" "    ints[i] <- val" "  }" "  ints" "}" "" "sample_from_upper <- function(z, a, b, ints) {" "  w <- cumsum(ints)" "  W <- w[length(w)]" "  u <- runif(1) * W" "  i <- which(w >= u)[1]" "  zl <- z[i]" "  zr <- z[i + 1]" "  ai <- a[i]" "  bi <- b[i]" "  if (abs(bi) < 1e-12) {" "    x <- zl + (zr - zl) * runif(1)" "  } else {" "    c0 <- exp(bi * zl)" "    x <- (1 / bi) * log(c0 + (u - c(sum(ints[seq_len(i - 1)]))) * bi / exp(ai))" "  }" "  # numerical guard to ensure x in (zl, zr)" "  x <- max(min(x, zr - 1e-12), zl + 1e-12)" "  list(x = x, idx = i, uval = ai + bi * x)" "}" "" "lower_hull_at <- function(x, xs, hs) {" "  # returns lower hull l(x) using secants between adjacent abscissae" "  n <- length(xs)" "  if (x <= xs[1] || x >= xs[n]) return(-Inf)" "  j <- findInterval(x, xs, left.open = FALSE, rightmost.closed = TRUE)" "  if (j == 0) j <- 1" "  if (j >= n) j <- n - 1" "  s <- (hs[j + 1] - hs[j]) / (xs[j + 1] - xs[j])" "  hs[j] + s * (x - xs[j])" "}" "" "check_log_concavity <- function(xs, hps) {" "  # For concave log-density, derivative should be non-increasing in x" "  all(diff(hps) < 1e-10)" "}" "" "init_abscissae <- function(logf, dlogf, lower, upper) {" "  # Try to find 3-5 initial abscissae with finite logf and decreasing slopes" "  # Start with symmetric points around 0 within domain" "  xs <- c(-1, 0, 1)" "  xs <- xs[is.finite(xs) & xs > lower & xs < upper]" "  if (length(xs) < 2) {" "    xs <- c((lower + upper)/2 - 0.5, (lower + upper)/2 + 0.5)" "    xs <- xs[is.finite(xs) & xs > lower & xs < upper]" "  }" "  # Ensure uniqueness and sorted" "  xs <- sort(unique(xs))" "  # Expand if needed" "  step <- 1" "  attempts <- 0" "  while (length(xs) < 3 && attempts < 50) {" "    attempts <- attempts + 1" "    cand <- c(min(xs) - step, max(xs) + step)" "    cand <- cand[cand > lower & cand < upper]" "    xs <- sort(unique(c(xs, cand)))" "    step <- step * 1.7" "  }" "  # Filter by finite logf" "  hs <- logf(xs)" "  keep <- is.finite(hs)" "  xs <- xs[keep]" "  hs <- hs[keep]" "  if (length(xs) < 2) stop('Could not find finite initial points within domain')" "  # Ensure we have at least 3 points by adding around edges" "  while (length(xs) < 3 && attempts < 100) {" "    attempts <- attempts + 1" "    newx <- c(min(xs) - step, max(xs) + step)" "    newx <- newx[newx > lower & newx < upper]" "    hnew <- logf(newx)" "    ok <- is.finite(hnew)" "    xs <- sort(unique(c(xs, newx[ok])))" "    step <- step * 1.7" "  }" "  xs <- sort(xs)" "  # Expand until left slope > 0 and right slope < 0 (for integrability on infinite tails)" "  for (iter in 1:50) {" "    hps <- dlogf(xs)" "    if (any(!is.finite(hps))) {" "      # nudge points" "      xs <- xs + rnorm(length(xs), 0, 1e-3)" "      next" "    }" "    ok_left <- if (is.infinite(lower)) hps[1] > 0 else TRUE" "    ok_right <- if (is.infinite(upper)) tail(hps, 1) < 0 else TRUE" "    if (ok_left && ok_right && length(xs) >= 3 && check_log_concavity(xs, hps)) break" "    # try to improve" "    if (!ok_left) {" "      newx <- max(lower, min(xs) - step)" "      if (newx > lower) xs <- sort(unique(c(xs, newx)))" "    }" "    if (!ok_right) {" "      newx <- min(uppe