t(xprop, xs, hs)" "    if (is.finite(l_at_x)) {" "      if (log(runif(1)) <= (l_at_x - u_at_x)) {" "        samp <- c(samp, xprop)" "        next" "      }" "    }" "    # Evaluate true log-density and acceptance" "    hx <- logf(xprop)" "    if (!is.finite(hx)) {" "      # reject and add to set if inside domain" "      xs <- sort(unique(c(xs, xprop)))" "      next" "    }" "    if (log(runif(1)) <= (hx - u_at_x)) {" "      samp <- c(samp, xprop)" "    }" "    # Update abscissae with proposed point" "    xs <- sort(unique(c(xs, xprop)))" "    # Sanity checks on updated derivative sequence" "    hps_new <- dlogf(xs)" "    if (any(!is.finite(hps_new))) stop('Non-finite derivative encountered during updates; possible non-log-concavity')" "    if (!check_log_concavity(xs, hps_new)) stop('Non-log-concave behavior detected during sampling updates')" "  }" "  samp" "}" "" "# ------------------- TESTING -------------------" "stats_summary <- function(x) {" "  c(mean = mean(x), sd = sd(x))" "}" "" "report <- function(name, pass, obs, exp_mean, exp_sd) {" "  status <- if (pass) 'PASS' else 'FAIL'" "  cat(sprintf('%s: %s (mean=%.4f, sd=%.4f, expected_mean=%.4f, expected_sd=%.4f)\n'," "             name, status, obs['mean'], obs['sd'], exp_mean, exp_sd))" "}" "" "test <- function() {" "  set.seed(123)") "  # Test 1: Standard Normal(0,1)" "  f_norm <- function(x) dnorm(x, 0, 1)" "  samps_n <- tryCatch(ars(f_norm, n = 5000, lower = -Inf, upper = Inf, seed = 42), error = function(e) e)" "  if (inherits(samps_n, 'error')) {" "    cat('NORMAL_SAMPLING: FAIL (', samps_n$message, ')\n', sep='')" "  } else {
    write.table(samps_n, file = '/app/normal_samples.txt', row.names = FALSE, col.names = FALSE)
