stats_summary <- function(x) {
  c(mean = mean(x), sd = sd(x))
}

report <- function(name, pass, obs, exp_mean, exp_sd) {
  status <- if (pass) 'PASS' else 'FAIL'
  cat(sprintf('%s: %s (mean=%.4f, sd=%.4f, expected_mean=%.4f, expected_sd=%.4f)\n',
              name, status, obs['mean'], obs['sd'], exp_mean, exp_sd))
}

test <- function() {
  set.seed(123)
  # Test 1: Standard Normal(0,1)
  f_norm <- function(x) dnorm(x, 0, 1)
  samps_n <- tryCatch(ars(f_norm, n = 5000, lower = -Inf, upper = Inf, seed = 42), error = function(e) e)
  if (inherits(samps_n, 'error')) {
    cat('NORMAL_SAMPLING: FAIL (', samps_n$message, ')\n', sep='')
  } else {
    write.table(samps_n, file = '/app/normal_samples.txt', row.names = FALSE, col.names = FALSE)
    obs <- stats_summary(samps_n)
    pass <- (abs(obs['mean'] - 0) < 0.05) && (abs(obs['sd'] - 1) < 0.05)
    report('NORMAL_SAMPLING', pass, obs, 0, 1)
  }
  # Test 2: Exponential(rate=1) on [0, Inf)
  f_exp <- function(x) ifelse(x >= 0, dexp(x, 1), 0)
  samps_e <- tryCatch(ars(f_exp, n = 5000, lower = 0, upper = Inf, seed = 123), error = function(e) e)
  if (inherits(samps_e, 'error')) {
    cat('EXPONENTIAL_SAMPLING: FAIL (', samps_e$message, ')\n', sep='')
  } else {
    obs <- stats_summary(samps_e)
    pass <- (abs(obs['mean'] - 1) < 0.05) && (abs(obs['sd'] - 1) < 0.05)
    report('EXPONENTIAL_SAMPLING', pass, obs, 1, 1)
  }
  # Test 3: Invalid n
  err_neg_n <- FALSE
  tryCatch({ ars(f_norm, n = -10) }, error = function(e) { err_neg_n <<- TRUE })
  cat(sprintf('INVALID_N_CHECK: %s\n', if (err_neg_n) 'PASS' else 'FAIL'))
  # Test 4: Non-log-concave density (mixture of normals)
  f_mix <- function(x) 0.5 * dnorm(x, -2, 1) + 0.5 * dnorm(x, 2, 1)
  got_err <- FALSE
  tryCatch({ invisible(ars(f_mix, n = 1000, lower = -Inf, upper = Inf)) }, error = function(e) { got_err <<- TRUE })
  cat(sprintf('NON_LOG_CONCAVE_CHECK: %s\n', if (got_err) 'PASS' else 'FAIL'))
}

