numeric_dlogf_factory <- function(logf, lower, upper) {
  function(x) {
    x <- as.numeric(x)
    eps <- 1e-6 * (1 + abs(x))
    xl <- x - eps
    xr <- x + eps
    # keep within domain
    xl <- pmax(xl, ifelse(is.finite(lower), lower + 1e-9, xl))
    xr <- pmin(xr, ifelse(is.finite(upper), upper - 1e-9, xr))
    # ensure xr > xl
