  if (!is.null(dlogf) && !is.function(dlogf)) stop('dlogf must be NULL or a function')
  invisible(TRUE)
}

make_logf <- function(f) {
  function(x) {
    y <- suppressWarnings(f(x))
    out <- rep(-Inf, length(x))
    ok <- is.finite(y) & (y > 0)
    out[ok] <- log(y[ok])
    out
  }
}

compute_intersections <- function(x, h, hp, lower, upper) {
  # compute z (intersection points) between tangents; z length = length(x)+1
  k <- length(x)
  z <- numeric(k + 1)
  z[1] <- lower
  z[k + 1] <- upper
  if (k >= 2) {
    for (i in 1:(k-1)) {
      denom <- hp[i] - hp[i + 1]
      num <- (h[i + 1] - h[i] - x[i + 1] * hp[i + 1] + x[i] * hp[i])
      if (!is.finite(denom) || !is.finite(num)) return(rep(NaN, k + 1))
      if (abs(denom) < 1e-12) {
        # If slopes equal and lines coincide (num ~ 0), use midpoint; else invalid
        if (abs(num) < 1e-10) {
          z[i + 1] <- 0.5 * (x[i] + x[i + 1])
        } else {
          return(rep(NaN, k + 1))
        }
      } else {
        z[i + 1] <- num / denom
      }
    }
  }
  if (any(!is.finite(z))) return(rep(NaN, k + 1))
  if (is.unsorted(z, strictly = TRUE)) return(rep(NaN, k + 1))
  z
}

build_upper_params <- function(x, h, hp) {
  # returns a (intercepts) and b (slopes) of tangents u(x) = a + b x at abscissae
  a <- h - hp * x
  list(a = a, b = hp)
}

segment_integrals <- function(z, a, b) {
  k <- length(a)
  ints <- numeric(k)
  for (i in 1:k) {
    bi <- b[i]
    ai <- a[i]
    zl <- z[i]
    zr <- z[i + 1]
    # integrability checks on infinite intervals
    if (is.infinite(zr) && bi >= 0) return(rep(NaN, k))
    if (is.infinite(zl) && bi <= 0) return(rep(NaN, k))
    if (abs(bi) < 1e-12) {
      val <- exp(ai) * (zr - zl)
    } else {
      val <- exp(ai) / bi * (exp(bi * zr) - exp(bi * zl))
    }
    if (!is.finite(val) || val <= 0) return(rep(NaN, k))
    ints[i] <- val
  }
  ints
}

sample_from_upper <- function(z, a, b, ints) {
  w <- cumsum(ints)
  W <- w[length(w)]
  u <- runif(1) * W
  i <- which(w >= u)[1]
  wl <- if (i == 1) 0 else w[i - 1]
  zl <- z[i]
  zr <- z[i + 1]
  ai <- a[i]
  bi <- b[i]
  u_piece <- (u - wl) / ints[i]
  if (abs(bi) < 1e-12) {
    x <- zl + (zr - zl) * u_piece
  } else {
    ezl <- exp(bi * zl)
    ezr <- exp(bi * zr)
    x <- (1 / bi) * log(ezl + u_piece * (ezr - ezl))
  }
  x <- max(min(x, zr - 1e-12), zl + 1e-12)
  list(x = x, uval = ai + bi * x)
}

lower_hull_at <- function(x, xs, hs) {
  # returns lower hull l(x) using secants between adjacent abscissae
  n <- length(xs)
  if (x <= xs[1] || x >= xs[n]) return(-Inf)
  j <- findInterval(x, xs, left.open = FALSE, rightmost.closed = TRUE)
  if (j <= 0) j <- 1
  if (j >= n) j <- n - 1
  s <- (hs[j + 1] - hs[j]) / (xs[j + 1] - xs[j])
  hs[j] + s * (x - xs[j])
}

check_log_concavity <- function(xs, hps) {
  # For concave log-density, derivative should be non-increasing in x
  all(diff(hps) <= 1e-8)
}

init_abscissae <- function(logf, dlogf, lower, upper) {
  xs <- numeric(0)
  if (is.finite(lower) && is.finite(upper)) {
    # pick 3 inner points
    delta <- (upper - lower) / 10
    a <- lower + delta
    b <- upper - delta
    xs <- sort(unique(c(a, (a + b)/2, b)))
  } else {
    xs <- c(-1, 0, 1)
    xs <- xs[xs > lower & xs < upper]
  }
  if (length(xs) < 2) {
    mid <- if (is.finite(lower) && is.finite(upper)) (lower + upper)/2 else 0
    xs <- sort(unique(c(mid - 1, mid, mid + 1)))
    xs <- xs[xs > lower & xs < upper]
  }
  # Expand until we have at least 3 finite-logf points
  step <- 1
  tries <- 0
  repeat {
    hs <- logf(xs)
    keep <- is.finite(hs)
    xs <- sort(unique(xs[keep]))
    if (length(xs) >= 3) break
    tries <- tries + 1
    if (tries > 50) break
    cand <- c(min(xs) - step, max(xs) + step)
    cand <- cand[cand > lower & cand < upper]
    xs <- sort(unique(c(xs, cand)))
    step <- step * 1.7
  }
  if (length(xs) < 3) stop('Could not find at least 3 finite initial points within domain')
  # Ensure derivative sequence is non-increasing; if not, add midpoints
  for (iter in 1:20) {
    hps <- dlogf(xs)
    if (any(!is.finite(hps))) {
      xs <- sort(unique(xs[is.finite(hps)]))
      next
    }
    ok_left <- if (is.infinite(lower)) hps[1] > 0 else TRUE
    ok_right <- if (is.infinite(upper)) tail(hps, 1) < 0 else TRUE
    if (ok_left && ok_right && check_log_concavity(xs, hps)) break
    mids <- sort(unique((xs[-1] + xs[-length(xs)]) / 2))
    mids <- mids[mids > lower & mids < upper]
    xs <- sort(unique(c(xs, mids)))
    xs <- xs[order(xs)]
    xs <- unique(xs)
    if (length(xs) > 20) break
  }
  xs
}

ars <- function(f, n, lower = -Inf, upper = Inf, dlogf = NULL, seed = NULL, max_iter = 100000) {
  validate_inputs(f, n, lower, upper, dlogf)
  if (!is.null(seed)) set.seed(seed)
  logf <- make_logf(f)
  if (is.null(dlogf)) dlogf <- numeric_dlogf_factory(logf, lower, upper)
  # Initialize abscissae
  xs <- init_abscissae(logf, dlogf, lower, upper)
  xs <- sort(xs)
  hs <- logf(xs)
  if (any(!is.finite(hs))) stop('Initial abscissae lead to -Inf log-density')
  hps <- dlogf(xs)
  if (any(!is.finite(hps))) stop('Non-finite derivative at initial points')
  if (!check_log_concavity(xs, hps)) stop('Detected non-log-concave behavior in initial derivative sequence')

  samp <- numeric(0)
  iters <- 0
  while (length(samp) < n) {
    iters <- iters + 1
    if (iters > max_iter) stop('Exceeded maximum iterations; sampling did not converge')
    # Recompute hull elements
    hs <- logf(xs)
    hps <- dlogf(xs)
    if (any(!is.finite(hs))) stop('Encountered -Inf logf at abscissae during updates')
    if (any(!is.finite(hps))) stop('Encountered non-finite derivative during updates')
    if (!check_log_concavity(xs, hps)) stop('Density not log-concave: derivative not non-increasing with x')

    up <- build_upper_params(xs, hs, hps)
    z <- compute_intersections(xs, hs, hps, lower, upper)
    if (any(!is.finite(z))) stop('Failed to compute valid intersections; likely non-log-concave or poor initialization')
    ints <- segment_integrals(z, up$a, up$b)
    if (any(!is.finite(ints))) stop('Upper hull not integrable on domain; check tails/log-concavity')

    # Sample from upper hull
    s <- sample_from_upper(z, up$a, up$b, ints)
    xprop <- s$x
    u_at_x <- s$uval

    # Squeezing test using lower hull
    l_at_x <- lower_hull_at(xprop, xs, hs)
    if (is.finite(l_at_x)) {
      if (log(runif(1)) <= (l_at_x - u_at_x)) {
        samp <- c(samp, xprop)
        next
      }
    }

    # Evaluate true log-density and acceptance test
    hx <- logf(xprop)
    if (!is.finite(hx)) {
      xs <- sort(unique(c(xs, xprop)))
      next
    }
    if (log(runif(1)) <= (hx - u_at_x)) {
      samp <- c(samp, xprop)
    }
    # Update abscissae with proposed point
    xs <- sort(unique(c(xs, xprop)))
    # Ensure concavity after update
    hps_new <- dlogf(xs)
    if (any(!is.finite(hps_new))) stop('Non-finite derivative encountered during updates; possible non-log-concavity')
    if (!check_log_concavity(xs, hps_new)) stop('Non-log-concave behavior detected during sampling updates')
  }
  samp
}

